var currentDate=new Date,currentYear=document.querySelector(".currentYear");currentYear.innerHTML=currentDate.getFullYear(),document.addEventListener("DOMContentLoaded",function(){var navBtnMobileOpen=document.querySelector(".mobileNav"),navBtnMobileClosed=document.querySelectorAll(".closed"),mobileNav=document.querySelector(".mobile");navBtnMobileOpen.onclick=function(){mobileNav.classList.add("mobileNavMovingOut"),mobileNav.classList.remove("mobileNavMovingIn")};for(let i=0;i<navBtnMobileClosed.length;i++)navBtnMobileClosed[i].onclick=function(){mobileNav.classList.add("mobileNavMovingIn"),mobileNav.classList.remove("mobileNavMovingOut")}},!1);